package github.chains;

import com.github.javaparser.*;
import com.github.javaparser.ast.*;
import com.github.javaparser.ast.body.*;
import com.github.javaparser.ast.expr.*;
import com.github.javaparser.ast.stmt.*;
import com.github.javaparser.ast.type.*;
import java.io.*;
import java.nio.charset.StandardCharsets;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        // Process all Java files in the source directory
        String sourceDir = args.length > 0 ? args[0] : "/workspace/fluxtion";
        processDirectory(new File(sourceDir));
    }

    private static void processDirectory(File dir) throws Exception {
        if (!dir.exists() || !dir.isDirectory()) {
            System.err.println("Invalid directory: " + dir);
            return;
        }

        File[] files = dir.listFiles((d, name) -> name.endsWith(".java"));
        if (files != null) {
            for (File file : files) {
                processFile(file);
            }
        }

        // Process subdirectories
        File[] subdirs = dir.listFiles(File::isDirectory);
        if (subdirs != null) {
            for (File subdir : subdirs) {
                processDirectory(subdir);
            }
        }
    }

    private static void processFile(File file) throws Exception {
        if (!file.getName().endsWith(".java")) {
            return;
        }

        // Parse the Java file
        CompilationUnit cu = StaticJavaParser.parse(file);
        boolean modified = false;

        // Find all constructor calls to SnakeYAML Constructor with no arguments
        modified = findAndReplaceSnakeYAMLConstructorCalls(cu) || modified;

        // If the file was modified, write it back
        if (modified) {
            try (OutputStream os = new FileOutputStream(file)) {
                String content = cu.toString();
                os.write(content.getBytes(StandardCharsets.UTF_8));
            }
            System.out.println("Modified: " + file.getAbsolutePath());
        }
    }

    private static boolean findAndReplaceSnakeYAMLConstructorCalls(CompilationUnit cu) {
        boolean found = false;

        // Find all constructor calls to org.yaml.snakeyaml.constructor.Constructor with no arguments
        cu.accept(new com.github.javaparser.ast.visitor.VoidVisitorAdapter<Void>() {
            @Override
            public void visit(ObjectCreationExpr objectCreation, Void arg) {
                // Check if this is a Constructor call
                if (objectCreation.getType().isClassOrInterfaceType()) {
                    ClassOrInterfaceType type = objectCreation.getType().asClassOrInterfaceType();
                    String typeName = type.getNameAsString();

                    if ("Constructor".equals(typeName) && 
                        type.getScope().isPresent() && 
                        type.getScope().get().toString().contains("snakeyaml.constructor")) {

                        // Check if it's a call with zero arguments (the problematic case)
                        if (objectCreation.getArguments().isEmpty()) {
                            // Replace with Constructor(new LoaderOptions())
                            objectCreation.setArguments(Arrays.asList(
                                new ObjectCreationExpr(
                                    new Name("org.yaml.snakeyaml.LoaderOptions"),
                                    new NodeList<>()
                                )
                            ));
                            found = true;
                        }
                    }
                }
                super.visit(objectCreation, arg);
            }
        }, null);

        return found;
    }
}

